CREATE TABLE tb_acompanhamento_projeto (
  id_acompanhamento_projeto INTEGER PRIMARY KEY AUTOINCREMENT,
  tarefas TEXT NOT NULL,
  aluno_responsavel TEXT NOT NULL,
  professor_da_area TEXT NOT NULL,
  inicio_previsto DATE NOT NULL,
  fim_previsto DATE NOT NULL,
  inicio_realizado DATE DEFAULT NULL,
  fim_realizado DATE DEFAULT NULL,
  duracao INTEGER DEFAULT NULL,
  status TEXT CHECK( status IN ('Não iniciado','Concluído','Em atraso','Necessitamos de auxílio') ) DEFAULT NULL,
  descricao_da_tarefa TEXT NOT NULL,
  dificuldades_enxergadas TEXT DEFAULT NULL,
  impacto_nas_outras TEXT DEFAULT NULL
, usuario TEXT DEFAULT NULL, comentario_empresa TEXT);
