CREATE TABLE tb_cronograma (
  id_cronograma INTEGER PRIMARY KEY,
  processo TEXT NOT NULL,
  etapas TEXT NOT NULL,
  responsavel TEXT NOT NULL,
  data_inicio DATE DEFAULT NULL,
  data_final DATE DEFAULT NULL,
  observacoes TEXT NOT NULL,
  usuario TEXT DEFAULT NULL,
  FOREIGN KEY (usuario) REFERENCES tb_cadastros (nome_usuarios) ON DELETE CASCADE ON UPDATE CASCADE,
  FOREIGN KEY (usuario) REFERENCES tb_equipe (nome_equipe) ON DELETE CASCADE ON UPDATE CASCADE,
  FOREIGN KEY (id_cronograma) REFERENCES tb_equipe (id_equipe) ON DELETE CASCADE ON UPDATE CASCADE
);
